Diagnose the primary performance bottleneck in this CUDA kernel
running on an NVIDIA A10G GPU (ridge point: 62 FLOP/byte).
```cuda
#include <cuda_runtime.h>
#include <cstdio>

__global__ void prefix_like_kernel(const float* a, const float* b, float* out, int n) {

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;
    while (idx < n - 8) {
        float acc = a[idx];
        #pragma unroll
        for (int offset = 1; offset <= 8; ++offset) {
            acc += a[idx + offset] * 0.0625f;
        }
        out[idx] = acc + b[idx] * 0.125f;
        idx += stride;
    }

}

int main() {
    const int n = 1 << 26;
    const size_t bytes = static_cast<size_t>(n) * sizeof(float);
    float *d_a, *d_b, *d_c;
    cudaMalloc(&d_a, bytes);
    cudaMalloc(&d_b, bytes);
    cudaMalloc(&d_c, bytes);
    cudaMemset(d_a, 1, bytes);
    cudaMemset(d_b, 2, bytes);
    cudaMemset(d_c, 0, bytes);
    prefix_like_kernel<<<4096, 256>>>(d_a, d_b, d_c, n);
    cudaDeviceSynchronize();
    prefix_like_kernel<<<4096, 256>>>(d_a, d_b, d_c, n);
    cudaDeviceSynchronize();
    float h = 0.0f;
    cudaMemcpy(&h, d_c, sizeof(float), cudaMemcpyDeviceToHost);
    printf("%f\n", h);
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_c);
    return 0;
}

```

What is the primary performance bottleneck?
Choose exactly one label:

memory-bound: kernel throughput is limited by memory bandwidth
  (DRAM utilization should be high, >50% of peak)
compute-bound: kernel throughput is limited by arithmetic units
  (arithmetic intensity above ridge point)
latency-bound: kernel is stalled waiting for dependent operations
  (long scoreboard stalls high, DRAM utilization LOW — distinct
  from memory-bound)
occupancy-limited: insufficient active warps to hide latency
  (achieved occupancy <35%, causing stalls)
register-spill: register pressure forces spilling to local memory
  (register count at max, local memory traffic visible)

